def insert(self, value):
    update = [self._HEAD] * (self.now_max_level + 1)
    node: Node | None = self._HEAD
    for i in range(self.now_max_level, -1, -1):
        while node.forward[i] and node.forward[i].data < value:
            node = node.forward[i]
        update[i] = node
    level = random.randint(0, self.now_max_level)
    if level > self.now_max_level:
        for i in range(self.now_max_level + 1, level + 1):
            update[i] = self._HEAD
        self.now_max_level = level
    new_node = Node(value, level)
    for i in range(level + 1):
        new_node.forward[i] = update[i].forward[i]
        update[i].forward[i] = new_node
    self._size += 1

